// Route an incoming email to the correct project based on subject/body
const email    = $('Monitor Inbox').first().json;
const projects = $('Load Project Registry').all().map(i => i.json);

const subject      = (email.subject     || '').toLowerCase().trim();
const bodyPreview  = (email.bodyPreview || '').toLowerCase().trim();
const sender       = (email.from?.emailAddress?.address || '').toLowerCase();
const senderName   = email.from?.emailAddress?.name   || sender;
const searchText   = subject + ' ' + bodyPreview;
const dateStr      = email.receivedDateTime
    ? new Date(email.receivedDateTime).toISOString().split('T')[0]
    : new Date().toISOString().split('T')[0];
const emailId      = email.id || '';

// Skip emails from self (sent-mail echoes)
if (sender.includes('hendricksoninc.com') && senderName === 'Buck Adams') {
    return [{ json: { skip: true, reason: 'sent by self', emailId } }];
}

// Skip marketing, newsletters, automated systems, spam
const spamDomains = ['mailchimp', 'constantcontact', 'sendgrid', 'klaviyo', 'mailerlite',
    'mandrillapp', 'amazonses', 'bounce', 'noreply', 'no-reply', 'donotreply',
    'notifications@', 'alerts@', 'newsletter', 'marketing', 'campaigns'];
const spamSubjectTerms = ['unsubscribe', 'click here to', 'view in browser',
    'email preferences', 'opt out', 'promotion', 'sale ends', 'limited time offer',
    'act now', 'special offer', 'congratulations you', 'you have been selected',
    'your account has been', 'verify your email', 'confirm your email'];
const spamBodyTerms = ['unsubscribe from', 'email preferences', 'view this email in'];

if (spamDomains.some(d => sender.includes(d))) {
    return [{ json: { skip: true, reason: 'marketing sender', emailId } }];
}
if (spamSubjectTerms.some(t => subject.includes(t))) {
    return [{ json: { skip: true, reason: 'marketing subject', emailId } }];
}
if (spamBodyTerms.some(t => bodyPreview.includes(t))) {
    return [{ json: { skip: true, reason: 'marketing body', emailId } }];
}

// Match to project
let matchedProject = null;
let matchScore = 0;
for (const p of projects) {
    const pName    = (p['Project Name'] || '').toLowerCase();
    const pAddress = (p['Address']      || '').toLowerCase();
    const pId      = (p['Project ID']   || '').toLowerCase();
    const aliases  = (p['Aliases']      || '').toLowerCase().split(',').map(a=>a.trim()).filter(Boolean);
    const terms    = [pName, pAddress, pId, ...aliases].filter(Boolean);
    const hits     = terms.filter(t => t && searchText.includes(t)).length;
    if (hits > matchScore) { matchScore = hits; matchedProject = p; }
}

if (!matchedProject) {
    return [{ json: {
        skip: false,
        routed: false,
        reason: 'No project matched',
        sender, senderName, subject: email.subject, dateStr, emailId,
    }}];
}

const projectName    = matchedProject['Project Name']    || 'Unknown';
const projectId      = matchedProject['Project ID']      || '';
const driveFolderId  = matchedProject['Drive Folder ID'] || matchedProject['Bid Folder ID'] || '';
const hasAttachment  = email.hasAttachments || false;

if (!driveFolderId) {
    return [{ json: {
        skip: false,
        routed: false,
        reason: `Project '${projectName}' matched but has no Drive Folder ID`,
        projectName, projectId, sender, senderName, subject: email.subject, dateStr, emailId,
    }}];
}

const memoName = `${dateStr}_Email_${senderName.replace(/[^a-zA-Z0-9]/g,'_').slice(0,30)}.txt`;
const memoBody = `From: ${senderName} <${sender}>
Date: ${email.receivedDateTime || dateStr}
Subject: ${email.subject}
Has Attachments: ${hasAttachment}

${email.bodyPreview || '(no preview)'}`;

return [{ json: {
    skip: false, routed: true,
    projectName, projectId, driveFolderId,
    sender, senderName, subject: email.subject || '',
    dateStr, emailId, hasAttachment, memoName, memoBody,
}}];

